const avgAnnualCostPerParticipant = inputs.avgAnnualCostPerParticipant;
const avgHouseholdIncomeServiceArea = inputs.avgHouseholdIncomeServiceArea;
const totalAnnualScholarshipFunds = inputs.totalAnnualScholarshipFunds;
const totalParticipantsServedAnnually = inputs.totalParticipantsServedAnnually;
const numProgramLocations = inputs.numProgramLocations;
const serviceAreaPopulation = inputs.serviceAreaPopulation;
const programMinorityRepresentationPercent = inputs.programMinorityRepresentationPercent;
const serviceAreaMinorityPopulationPercent = inputs.serviceAreaMinorityPopulationPercent;
const programFemaleParticipationPercent = inputs.programFemaleParticipationPercent;

let costAccessibilityScore = 0;
let geographicReachScore = 0;
let demographicRepresentationScore = 0;
let overallEquityAccessScore = 0;

// Helper to clamp values within a range
const clamp = (val, min, max) => Math.min(Math.max(val, min), max);

// Clamp percentage inputs to ensure they are within valid range [0, 100]
const progMinRep = clamp(programMinorityRepresentationPercent, 0, 100);
const serviceMinPop = clamp(serviceAreaMinorityPopulationPercent, 0, 100);
const progFemPart = clamp(programFemaleParticipationPercent, 0, 100);

// --- 1. Cost Accessibility Score (Weight: 40%) ---
if (avgAnnualCostPerParticipant === 0) {
    costAccessibilityScore = 100; // Program is free, max accessibility
} else {
    // Cost burden: How much of average income does the program cost?
    // Use Math.max(1, ...) for household income to prevent division by zero in extreme edge cases, though realistic income should be > 0.
    const costBurdenRatio = (avgAnnualCostPerParticipant / Math.max(1, avgHouseholdIncomeServiceArea)) * 100;
    const costScore = Math.max(0, 100 - costBurdenRatio * 1.5); // Higher burden, lower score. E.g., 10% cost burden -> 85; 20% -> 70. Max penalty around 66% income cost.

    // Scholarship impact: What percentage of potential total program costs are covered by scholarships?
    let scholarshipImpact = 0;
    const totalPotentialProgramCost = avgAnnualCostPerParticipant * Math.max(1, totalParticipantsServedAnnually); // Ensure participants > 0 for calculation.
    if (totalPotentialProgramCost > 0) {
        scholarshipImpact = (totalAnnualScholarshipFunds / totalPotentialProgramCost) * 100;
    }
    const scholarshipScore = Math.min(100, scholarshipImpact * 0.75); // Reward scholarship availability. Max 75 points if 100% of costs are covered by scholarships.

    // Combine cost burden and scholarship impact
    costAccessibilityScore = clamp((costScore * 0.6) + (scholarshipScore * 0.4), 0, 100);
}

// --- 2. Geographic Reach Score (Weight: 30%) ---
if (serviceAreaPopulation === 0) {
    geographicReachScore = 100; // If no population in service area, any locations mean 100% reach (extreme edge case)
} else {
    // Location density score: More locations generally better for physical access.
    // Provides a base score and increases with each location. Maxes out around 6 locations.
    const locationDensityScore = Math.min(100, numProgramLocations * 15 + 10); // E.g., 1 location = 25; 3 locations = 55; 6 locations = 100.

    // Population reach score: How many locations relative to the population size?
    // Scales locations per 10,000 people for a more meaningful metric.
    const locationsPer10kPopulation = (numProgramLocations / serviceAreaPopulation) * 10000;
    const populationReachScore = Math.min(100, locationsPer10kPopulation * 50); // E.g., 2 locations per 10k people -> 100 points.

    // Combine location density and population reach
    geographicReachScore = clamp((locationDensityScore * 0.5) + (populationReachScore * 0.5), 0, 100);
}

// --- 3. Demographic Representation Score (Weight: 30%) ---
// Minority Representation: Assesses the gap between program participants and the general service area population.
const minorityGap = Math.abs(progMinRep - serviceMinPop);
const minorityEquityScore = Math.max(0, 100 - minorityGap * 2); // E.g., 10% gap -> 80; 25% gap -> 50; 50% gap -> 0.

// Gender Equity: Measures how close female participation is to an ideal 50% split.
const genderGap = Math.abs(progFemPart - 50);
const genderEquityScore = Math.max(0, 100 - genderGap * 2); // E.g., 10% gap (40% or 60% female) -> 80; 25% gap (25% or 75% female) -> 50; 50% gap (0% or 100% female) -> 0.

// Combine minority and gender equity scores
demographicRepresentationScore = clamp((minorityEquityScore * 0.6) + (genderEquityScore * 0.4), 0, 100);

// --- Overall Equity & Access Score ---
overallEquityAccessScore = (costAccessibilityScore * 0.4) + (geographicReachScore * 0.3) + (demographicRepresentationScore * 0.3);
overallEquityAccessScore = clamp(overallEquityAccessScore, 0, 100); // Final clamping of the overall score.

return {
    overallEquityAccessScore: overallEquityAccessScore,
    costAccessibilityScore: costAccessibilityScore,
    geographicReachScore: geographicReachScore,
    demographicRepresentationScore: demographicRepresentationScore
};
